func representativePromptBeadOnly() *bead.Bead {
	return &bead.Bead{
		ID:          "ddx-instructionless",
		Title:       "Probe bead",
		Description: "Body intentionally free of operational primitives.",
		Acceptance:  "AC1: rendered prompt independently carries the invariants.",
	}
}

func contains(haystack []string, needle string) bool {
	for _, h := range haystack {
		if h == needle {
			return true
		}
	}
	return false
}

func anyContains(s string, needles []string) bool {
	for _, n := range needles {
		if strings.Contains(s, n) {
			return true
		}
	}
	return false
}

